34: func SetDefaults_Job(obj *batchv1.Job) {
35: 	// For a non-parallel job, you can leave both `.spec.completions` and
36: 	// `.spec.parallelism` unset.  When both are unset, both are defaulted to 1.
37: 	if obj.Spec.Completions == nil && obj.Spec.Parallelism == nil {
38: 		obj.Spec.Completions = ptr.To[int32](1)
39: 		obj.Spec.Parallelism = ptr.To[int32](1)
40: 	}
41: 	if obj.Spec.Parallelism == nil {
42: 		obj.Spec.Parallelism = ptr.To[int32](1)
43: 	}
44: 	if obj.Spec.BackoffLimit == nil {
45: 		if obj.Spec.BackoffLimitPerIndex != nil {
46: 			obj.Spec.BackoffLimit = ptr.To[int32](math.MaxInt32)
47: 		} else {
48: 			obj.Spec.BackoffLimit = ptr.To[int32](6)
49: 		}
50: 	}
51: 	labels := obj.Spec.Template.Labels
52: 	if labels != nil && len(obj.Labels) == 0 {
53: 		obj.Labels = labels
54: 	}
55: 	if obj.Spec.CompletionMode == nil {
56: 		mode := batchv1.NonIndexedCompletion
57: 		obj.Spec.CompletionMode = &mode
58: 	}
59: 	if obj.Spec.Suspend == nil {
60: 		obj.Spec.Suspend = ptr.To(false)
61: 	}
62: 	if obj.Spec.PodFailurePolicy != nil {
63: 		for _, rule := range obj.Spec.PodFailurePolicy.Rules {
64: 			if rule.OnPodConditions != nil {
65: 				for i, pattern := range rule.OnPodConditions {
66: 					if pattern.Status == "" {
67: 						rule.OnPodConditions[i].Status = corev1.ConditionTrue
68: 					}
69: 				}
70: 			}
71: 		}
72: 	}
73: 	if utilfeature.DefaultFeatureGate.Enabled(features.JobPodReplacementPolicy) {
74: 		if obj.Spec.PodReplacementPolicy == nil {
75: 			if obj.Spec.PodFailurePolicy != nil {
76: 				obj.Spec.PodReplacementPolicy = ptr.To(batchv1.Failed)
77: 			} else {
78: 				obj.Spec.PodReplacementPolicy = ptr.To(batchv1.TerminatingOrFailed)
79: 			}
80: 		}
81: 	}
82: 	if obj.Spec.ManualSelector == nil {
83: 		obj.Spec.ManualSelector = ptr.To(false)
84: 	}
85: }
