95: 		obj.Spec.SuccessfulJobsHistoryLimit = ptr.To[int32](3)
96: 	}
97: 	if obj.Spec.FailedJobsHistoryLimit == nil {
98: 		obj.Spec.FailedJobsHistoryLimit = ptr.To[int32](1)
99: 	}
